function solve(nums) {
    const N = nums.length;
    if (N < 3) {
        return 0;
    }

    const N_potential = N - 2;
    // M is the maximum possible number of special indices (size of the maximum independent set on potential indices)
    const M = Math.ceil(N_potential / 2);

    /**
     * Calculates the total cost and size of the set of peaks for a given starting index pattern.
     * @param {number} start The starting index (1 or 2) of the peaks.
     * @returns {{cost: number, size: number}} Object containing total cost and the size of the peak set.
     */
    function calculate_cost(start) {
        let cost = 0;
        let current_size = 0;

        // Iterate over the sequence i = start, start+2, start+4, ... up to N-2
        for (let i = start; i <= N - 2; i += 2) {
            current_size++;

            // For i to be a peak, nums[i] must be > nums[i-1] and > nums[i+1].
            // Since the set of target peaks is non-adjacent, neighbors i-1 and i+1 are not peaks,
            // and thus their values remain unchanged by modifications within this set calculation.

            const L = nums[i - 1];
            const R = nums[i + 1];

            // Required minimum value for nums[i]
            const required = Math.max(L, R) + 1;

            const current_val = nums[i];

            if (current_val < required) {
                const increase = required - current_val;
                cost += increase;
            }
        }
        return { cost: cost, size: current_size };
    }

    // Calculate results for Pattern 1 (starts at 1: {1, 3, 5, ...})
    const result1 = calculate_cost(1);

    // Calculate results for Pattern 2 (starts at 2: {2, 4, 6, ...})
    const result2 = calculate_cost(2);

    let min_cost = Infinity;

    // Check Pattern 1: Must achieve the maximum count M
    if (result1.size === M) {
        min_cost = Math.min(min_cost, result1.cost);
    }

    // Check Pattern 2: Must achieve the maximum count M
    if (result2.size === M) {
        min_cost = Math.min(min_cost, result2.cost);
    }

    return min_cost;
}

