fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n < 3 {
        return 0;
    }

    // Helper function equivalent to calculate_cost in JS
    // Returns (total_cost, achieved_size)
    let calculate_cost = |start: usize| -> (i64, i64) {
        let mut cost: i64 = 0;
        let mut current_size: i64 = 0;

        // Potential peaks range from index 1 to N-2 (inclusive)
        let end_index = n - 2;

        if end_index < start {
            return (0, 0);
        }

        let mut i = start;
        while i <= end_index {
            current_size += 1;

            // Since i >= 1 and i <= N-2, neighbors i-1 and i+1 are valid indices.

            let l = nums[i - 1];
            let r = nums[i + 1];

            // Required minimum value for nums[i] to be a peak
            // required = max(L, R) + 1
            let required = l.max(r) + 1;

            let current_val = nums[i];

            if current_val < required {
                let increase = required - current_val;
                cost += increase;
            }

            i += 2;
        }
        (cost, current_size)
    };

    // Maximum possible number of special indices M = ceil((N-2)/2)
    let n_potential = (n - 2) as i64;
    let m = (n_potential + 1) / 2;

    // Calculate results for Pattern 1 (starts at index 1: {1, 3, 5, ...})
    let result1 = calculate_cost(1);

    // Calculate results for Pattern 2 (starts at index 2: {2, 4, 6, ...})
    let result2 = calculate_cost(2);

    let mut min_cost = std::i64::MAX;

    // Check Pattern 1: Must achieve the maximum count M
    if result1.1 == m {
        min_cost = min_cost.min(result1.0);
    }

    // Check Pattern 2: Must achieve the maximum count M
    if result2.1 == m {
        min_cost = min_cost.min(result2.0);
    }

    // If M=0 (only possible if N<3, which is handled), min_cost remains MAX, but since N>=3, M>=1.
    // If for some reason M=1 but neither pattern achieves it (which shouldn't happen for N>=3), 
    // we rely on the fact that at least one pattern achieving M must exist based on the problem constraints/theory.
    // Since we checked the two maximal sets, one must satisfy the condition if M is the achievable maximum.

    min_cost
}

